def publish_message(
    topic_arn: str,
    message: Any,
    subject: str,
    notification_type: str,
    message_attributes: Dict[str, Any]
) -> Dict[str, Any]:
    """
    Publish a message to SNS topic based on notification type.
    """
    
    # Prepare message content
    message_body = prepare_message_body(message, notification_type)
    
    # Prepare message attributes
    formatted_attributes = format_message_attributes(message_attributes)
    
    # Add default attributes
    formatted_attributes['notification_type'] = {
        'DataType': 'String',
        'StringValue': notification_type
    }
    formatted_attributes['timestamp'] = {
        'DataType': 'String',
        'StringValue': datetime.utcnow().isoformat()
    }
    
    # Publish based on notification type
    if notification_type == 'email':
        return publish_email_notification(topic_arn, message_body, subject, formatted_attributes)
    elif notification_type == 'sms':
        return publish_sms_notification(topic_arn, message_body, formatted_attributes)
    elif notification_type == 'application':
        return publish_application_notification(topic_arn, message_body, formatted_attributes)
    elif notification_type == 'all':
        return publish_all_protocols(topic_arn, message_body, subject, formatted_attributes)
    else:
        # Default to simple publish
        return publish_simple(topic_arn, message_body, subject, formatted_attributes)


def prepare_message_body(message: Any, notification_type: str) -> str:
    """
    Prepare message body based on type and notification protocol.
    """
    if isinstance(message, dict):
        # For structured messages, create protocol-specific formats
        if notification_type == 'all':
            return json.dumps({
                'default': json.dumps(message) if not isinstance(message.get('default'), str) else message.get('default', str(message)),
                'email': message.get('email', json.dumps(message, indent=2)),
                'sms': message.get('sms', str(message)[:140]),  # SMS limit
                'http': message.get('http', json.dumps(message)),
                'https': message.get('https', json.dumps(message)),
                'sqs': message.get('sqs', json.dumps(message)),
                'lambda': message.get('lambda', json.dumps(message))
            })
        else:
            return json.dumps(message)
    else:
        return str(message)


def publish_simple(
    topic_arn: str,
    message: str,
    subject: str,
    message_attributes: Dict[str, Any]
) -> Dict[str, Any]:
    """
    Simple message publish to SNS topic.
    """
    response = sns_client.publish(
        TopicArn=topic_arn,
        Message=message,
        Subject=subject,
        MessageAttributes=message_attributes
    )
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'simple'
    }


def publish_email_notification(
    topic_arn: str,
    message: str,
    subject: str,
    message_attributes: Dict[str, Any]
) -> Dict[str, Any]:
    """
    Publish email-specific notification.
    """
    # For email, we can use a structured message
    email_message = message
    if not message.startswith('{'):
        # Simple text message
        email_message = message
    else:
        # Try to extract email-specific format
        try:
            msg_dict = json.loads(message)
            if 'email' in msg_dict:
                email_message = msg_dict['email']
            elif 'default' in msg_dict:
                email_message = msg_dict['default']
        except:
            pass
    
    response = sns_client.publish(
        TopicArn=topic_arn,
        Message=email_message,
        Subject=subject,
        MessageAttributes=message_attributes
    )
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'email',
        'subject': subject
    }


def publish_sms_notification(
    topic_arn: str,
    message: str,
    message_attributes: Dict[str, Any]
) -> Dict[str, Any]:
    """
    Publish SMS-specific notification.
    """
    # Extract SMS message if in structured format
    sms_message = message
    if message.startswith('{'):
        try:
            msg_dict = json.loads(message)
            if 'sms' in msg_dict:
                sms_message = msg_dict['sms']
            elif 'default' in msg_dict:
                sms_message = msg_dict['default']
        except:
            pass
    
    # Truncate to SMS limit
    sms_message = sms_message[:160]
    
    # Add SMS-specific attributes
    message_attributes['AWS.SNS.SMS.SMSType'] = {
        'DataType': 'String',
        'StringValue': 'Transactional'  # or 'Promotional'
    }
    
    response = sns_client.publish(
        TopicArn=topic_arn,
        Message=sms_message,
        MessageAttributes=message_attributes
    )
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'sms',
        'message_length': len(sms_message)
    }


def publish_application_notification(
    topic_arn: str,
    message: str,
    message_attributes: Dict[str, Any]
) -> Dict[str, Any]:
    """
    Publish application/mobile push notification.
    """
    # For mobile applications, structure the message appropriately
    app_message = message
    
    # If message is already structured, use it
    if message.startswith('{'):
        app_message = message
    else:
        # Create a structured message for mobile platforms
        app_message = json.dumps({
            'default': message,
            'GCM': json.dumps({
                'notification': {
                    'title': 'Notification',
                    'body': message
                }
            }),
            'APNS': json.dumps({
                'aps': {
                    'alert': message,
                    'sound': 'default'
                }
            })
        })
    
    response = sns_client.publish(
        TopicArn=topic_arn,
        Message=app_message,
        MessageStructure='json',
        MessageAttributes=message_attributes
    )
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'application'
    }


def publish_all_protocols(
    topic_arn: str,
    message: str,
    subject: str,
    message_attributes: Dict[str, Any]
) -> Dict[str, Any]:
    """
    Publish to all protocol types with structured message.
    """
    # Message should already be in structured format from prepare_message_body
    response = sns_client.publish(
        TopicArn=topic_arn,
        Message=message,
        Subject=subject,
        MessageStructure='json',
        MessageAttributes=message_attributes
    )
    
    return {
        'message_id': response['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': 'all',
        'subject': subject
    }


def handle_batch_messages(event: Dict[str, Any]) -> Dict[str, Any]:
    """
    Handle batch message publishing.
    """
    topic_arn = event.get('topic_arn')
    batch_messages = event.get('batch_messages', [])
    notification_type = event.get('notification_type', 'all')
    
    if not topic_arn:
        return create_error_response('topic_arn is required for batch messages', 400)
    
    if not batch_messages:
        return create_error_response('batch_messages cannot be empty', 400)
    
    results = []
    errors = []
    
    for idx, msg_data in enumerate(batch_messages):
        try:
            message = msg_data.get('message')
            subject = msg_data.get('subject', f'Notification {idx + 1}')
            msg_attributes = msg_data.get('message_attributes', {})
            msg_type = msg_data.get('notification_type', notification_type)
            
            if not message:
                errors.append({
                    'index': idx,
                    'error': 'message is required'
                })
                continue
            
            result = publish_message(
                topic_arn=topic_arn,
                message=message,
                subject=subject,
                notification_type=msg_type,
                message_attributes=msg_attributes
            )
            
            results.append({
                'index': idx,
                'result': result
            })
            
        except Exception as e:
            errors.append({
                'index': idx,
                'error': str(e)
            })
    
    return {
        'statusCode': 200 if not errors else 207,  # 207 Multi-Status
        'body': json.dumps({
            'success': True,
            'total': len(batch_messages),
            'successful': len(results),
            'failed': len(errors),
            'results': results,
            'errors': errors
        })
    }


def format_message_attributes(attributes: Dict[str, Any]) -> Dict[str, Any]:
    """
    Format message attributes to SNS required format.
    """
    formatted = {}
    
    for key, value in attributes.items():
        if isinstance(value, dict) and 'DataType' in value:
            # Already in correct format
            formatted[key] = value
        else:
            # Auto-detect type and format
            if isinstance(value, (int, float)):
                formatted[key] = {
                    'DataType': 'Number',
                    'StringValue': str(value)
                }
            else:
                formatted[key] = {
                    'DataType': 'String',
                    'StringValue': str(value)
                }
    
    return formatted


def create_success_response(data: Dict[str, Any]) -> Dict[str, Any]:
    """
    Create a success response.
    """
    return {
        'statusCode': 200,
        'body': json.dumps({
            'success': True,
            'data': data,
            'timestamp': datetime.utcnow().isoformat()
        })
    }


def create_error_response(error_message: str, status_code: int = 500) -> Dict[str, Any]:
    """
    Create an error response.
    """
    return {
        'statusCode': status_code,
        'body': json.dumps({
            'success': False,
            'error': error_message,
            'timestamp': datetime.utcnow().isoformat()
        })
    }